var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"보이시나요? 이젠 손쉽게 한기를 다스릴 수 있게 되었습니다.","JPN":"見えますか？　もう自在に冷気を扱えるようになりました。","ENG":"Do you see this? I can now control the cold with ease.","TWN":"您有看到嗎？我現在已經可以輕易操控寒氣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"늘 바라왔던 일이었는데…… 한 가지 착각한 게 있더군요.","JPN":"ずっと望んでいたことでしたが……勘違いがひとつありました。","ENG":"This is something I have always wanted... But there is one I was wrong about.","TWN":"這是我一直以來所期待的……但我似乎誤會一件事。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"한기를 다스린다 해서 추위가 가시는 게 아니라는 것을요.","JPN":"冷気を扱えても寒さが無くなることはないということです。","ENG":"Being able to control the cold did not mean that it would go away.","TWN":"原來可以操控寒氣不代表寒意會消失。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"여전히 제 주변은 얼어붙어 있고, 숨 마디마디에 서리가 내려 앉습니다.","JPN":"いまだに私の周りは凍り付いていて、息をするたびに霜が下ります。","ENG":"Everything around me is still frozen, and I can see my breath whenever I exhale.","TWN":"我的周圍依舊冰冰冷冷，每一口呼吸都會結霜。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"호기심 어린 시선으로 세상을 바라보던 지난 날로는 더 이상 되돌아 갈 수 없게 된 거죠.","JPN":"好奇心旺盛な目で世の中を見つめていた日々には、もう戻れなくなったのです。","ENG":"This just means that I can no longer return to the days when I looked at the world with awe.","TWN":"現在的我，已經回不去那個過去帶著好奇心看世界的我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"머릿속에 스며든 지식의 영역이 넓어지면 넓어질수록 제 안의 다른 영역이 점점 좁아지는 게 느껴져요.","JPN":"頭の中に染み込んだ知識の領域が広くなればなるほど、私の中の他の領域が少しずつ狭くなるのを感じるのです。","ENG":"As more knowledge expands in my head, I feel the other areas in me getting smaller.","TWN":"我發現滲入我腦海中的知識佔據的空間越大，我裡面其他的空間就會越小。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그건… 아마도 인간이 가진 온기……. 금방이라도 상실해 버릴까 두려워 오히려 외면하게 되더군요.","JPN":"それは……たぶん人間本来が持つ温もりでしょう……今にも喪失してしまいそうで怖くて見ないふりをするようになりました。","ENG":"Perhaps... That would be my human heart... I am terrified I might lose it so I tend to shy away.","TWN":"而那個縮小的空間…似乎就是屬於人類的溫度……因為太害怕它瞬間就會消失不見，只好選擇不正視它。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"관리자님 말씀이 옳습니다. 제게 인간성이 아직 남아 있기에 저런 두려움도 지닐 수 있다는 말씀이시죠.","JPN":"管理者様のおっしゃっるとおりです。私の人間性がまだ残っているために、恐ろしさも感じることができるのですね。","ENG":"The Administrator was right. I am able to feel fear because of my humanity.","TWN":"您說的沒錯，就是因為我還保有人性，才會產生害怕的想法。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"……그러고 보니 방 안이 따뜻하네요. 제가 온다고 관리자님께서 신경 써 주셨군요.","JPN":"……そういえば、部屋が温かいですね。私のために管理者様が気を使ってくださったのですね。","ENG":"...Now that I think of it, this room is pretty warm. Did you do this because I said I was coming over?","TWN":"……不過話說回來，房間裡很溫暖呢。是因為我要來，您才特別費心安排的吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"훗. 그러실 필요 없어요. 관리자님과 짧은 대화를 나누는 것만으로도 전 온기를 느끼니까요.","JPN":"ふっ。そうなさる必要はありません。管理者様と軽く会話を交わすだけでも私は温もりを感じるのですから。","ENG":"Haha. You are too kind. Just having this short conversation with you is already making me feel warm, Administrator.","TWN":"呵，不需要這樣，因為光是和您對話就可以讓我感受到溫暖。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};